import React, { useEffect, useState } from 'react';
import { api } from '../utils/api';

// No mock traders — empty state shown when API is unavailable

const VerifiedLeaderboard = () => {
  const [traders, setTraders] = useState([]);
  const [filter, setFilter] = useState('all'); // all or verified
  const [sortKey, setSortKey] = useState('return30d'); // return30d, winRate, followers
  const [sortDesc, setSortDesc] = useState(true);
  const [following, setFollowing] = useState({});

  useEffect(() => {
    let mounted = true;
    api('/leaderboard')
      .then((data) => {
        if (mounted && Array.isArray(data)) setTraders(data);
        else if (mounted) setTraders([]);
      })
      .catch(() => {
        if (mounted) setTraders([]);
      });
    return () => {
      mounted = false;
    };
  }, []);

  const filtered = traders.filter((t) => (filter === 'verified' ? t.verified : true));

  const sorted = filtered.slice().sort((a, b) => {
    let aVal = a[sortKey];
    let bVal = b[sortKey];
    if (sortKey === 'return30d' || sortKey === 'winRate') {
      aVal = Number(aVal);
      bVal = Number(bVal);
    }
    if (sortDesc) return bVal - aVal;
    return aVal - bVal;
  });

  const toggleFollow = (username) => {
    setFollowing((f) => ({
      ...f,
      [username]: !f[username],
    }));
  };

  const getBadge = (rank) => {
    if (rank === 1)
      return (
        <span
          aria-label="Gold badge"
          title="Gold badge"
          style={{ color: '#F59E0B', marginRight: 8, fontSize: 18 }}
        >
          🥇
        </span>
      );
    if (rank === 2)
      return (
        <span
          aria-label="Silver badge"
          title="Silver badge"
          style={{ color: '#90A3AF', marginRight: 8, fontSize: 18 }}
        >
          🥈
        </span>
      );
    if (rank === 3)
      return (
        <span
          aria-label="Bronze badge"
          title="Bronze badge"
          style={{ color: '#EF4444', marginRight: 8, fontSize: 18 }}
        >
          🥉
        </span>
      );
    return null;
  };

  return (
    <>
      <style>{`
        @import url('https://fonts.googleapis.com/css2?family=JetBrains+Mono&display=swap');
        * {
          box-sizing: border-box;
        }
        .leaderboard {
          font-family: 'JetBrains Mono', monospace;
          background-color: #0B0F14;
          color: #E5E7DB;
          padding: 20px;
          border-radius: 8px;
          max-width: 100%;
          overflow-x: auto;
          user-select: none;
        }
        .tabs {
          display: flex;
          gap: 12px;
          margin-bottom: 16px;
        }
        .tab {
          cursor: pointer;
          padding: 8px 16px;
          border-radius: 6px;
          border: 1px solid #1F2A37;
          background-color: #0F1620;
          color: #90A3AF;
          transition: background-color 0.25s, color 0.25s;
          user-select: none;
        }
        .tab.active {
          background-color: #60A5FA;
          color: #0B0F14;
          border-color: #60A5FA;
          font-weight: 600;
        }
        .sort-select {
          margin-left: auto;
          background-color: #0F1620;
          border: 1px solid #1F2A37;
          color: #E5E7DB;
          padding: 6px 12px;
          border-radius: 6px;
          font-family: 'JetBrains Mono', monospace;
          cursor: pointer;
          user-select: none;
        }
        table {
          width: 100%;
          border-collapse: collapse;
          min-width: 720px;
        }
        thead {
          background-color: #0F1620;
        }
        th, td {
          padding: 12px 10px;
          border-bottom: 1px solid #1F2A37;
          text-align: left;
          vertical-align: middle;
          white-space: nowrap;
        }
        th {
          font-weight: 600;
          font-size: 14px;
          color: #90A3AF;
          user-select: none;
        }
        tbody tr:hover {
          background-color: #16202B;
        }
        .verified-badge {
          color: #60A5FA;
          margin-left: 6px;
          vertical-align: middle;
          font-size: 14px;
        }
        .strategy-tag {
          background-color: #1F2A37;
          color: #90A3AF;
          padding: 2px 8px;
          border-radius: 12px;
          font-size: 12px;
          user-select: none;
        }
        .return-positive {
          color: #22C55E;
          font-weight: 600;
        }
        .return-negative {
          color: #EF4444;
          font-weight: 600;
        }
        .follow-button {
          background-color: transparent;
          border: 1px solid #60A5FA;
          color: #60A5FA;
          padding: 6px 14px;
          border-radius: 6px;
          font-family: 'JetBrains Mono', monospace;
          font-weight: 600;
          cursor: pointer;
          user-select: none;
          transition: background-color 0.25s, color 0.25s;
        }
        .follow-button.following {
          background-color: #60A5FA;
          color: #0B0F14;
          border-color: #60A5FA;
        }
        .follow-button:hover {
          background-color: #60A5FA;
          color: #0B0F14;
          border-color: #60A5FA;
        }
        .sort-container {
          display: flex;
          align-items: center;
          margin-bottom: 12px;
          gap: 12px;
          flex-wrap: wrap;
        }
        .sort-label {
          color: #90A3AF;
          font-size: 14px;
          user-select: none;
        }
        .sort-direction {
          cursor: pointer;
          user-select: none;
          color: #60A5FA;
          font-weight: 700;
          font-size: 18px;
          line-height: 1;
          display: inline-flex;
          align-items: center;
          justify-content: center;
          width: 20px;
          height: 20px;
          border-radius: 4px;
          border: 1px solid #60A5FA;
          transition: background-color 0.25s, color 0.25s;
        }
        .sort-direction:hover {
          background-color: #60A5FA;
          color: #0B0F14;
        }
      `}</style>
      <section className="leaderboard" aria-label="Aura Alpha Social Trading Leaderboard">
        <div className="tabs" role="tablist" aria-label="Filter traders">
          <button
            role="tab"
            aria-selected={filter === 'all'}
            tabIndex={filter === 'all' ? 0 : -1}
            className={`tab${filter === 'all' ? ' active' : ''}`}
            onClick={() => setFilter('all')}
            type="button"
          >
            All
          </button>
          <button
            role="tab"
            aria-selected={filter === 'verified'}
            tabIndex={filter === 'verified' ? 0 : -1}
            className={`tab${filter === 'verified' ? ' active' : ''}`}
            onClick={() => setFilter('verified')}
            type="button"
          >
            Verified Only
          </button>
          <div className="sort-container" style={{ marginLeft: 'auto' }}>
            <label htmlFor="sort-select" className="sort-label">
              Sort by:
            </label>
            <select
              id="sort-select"
              className="sort-select"
              value={sortKey}
              onChange={(e) => setSortKey(e.target.value)}
              aria-label="Sort traders by"
            >
              <option value="return30d">Return (30d)</option>
              <option value="winRate">Win Rate</option>
              <option value="followers">Followers</option>
            </select>
            <button
              type="button"
              aria-label={sortDesc ? 'Sort descending' : 'Sort ascending'}
              className="sort-direction"
              onClick={() => setSortDesc((d) => !d)}
            >
              {sortDesc ? '↓' : '↑'}
            </button>
          </div>
        </div>
        <table role="table" aria-describedby="leaderboard-desc">
          <caption id="leaderboard-desc" style={{ position: 'absolute', left: '-9999px', height: 1, width: 1, overflow: 'hidden' }}>
            Social trading leaderboard showing top traders with rank, username, verified badge, 30 day return percentage, win rate, total trades, follower count, strategy style tag, and follow button.
          </caption>
          <thead>
            <tr>
              <th scope="col" style={{ width: 60, textAlign: 'center' }}>#</th>
              <th scope="col" style={{ minWidth: 140 }}>Trader</th>
              <th scope="col" style={{ width: 110, textAlign: 'right' }}>30d Return</th>
              <th scope="col" style={{ width: 90, textAlign: 'right' }}>Win Rate</th>
              <th scope="col" style={{ width: 90, textAlign: 'right' }}>Trades</th>
              <th scope="col" style={{ width: 110, textAlign: 'right' }}>Followers</th>
              <th scope="col" style={{ minWidth: 110 }}>Strategy</th>
              <th scope="col" style={{ width: 110, textAlign: 'center' }}>Follow</th>
            </tr>
          </thead>
          <tbody>
            {sorted.map((t) => {
              const isPositiveReturn = Number(t.return30d) >= 0;
              return (
                <tr key={t.username}>
                  <td style={{ textAlign: 'center', fontWeight: '600' }}>
                    {getBadge(t.rank)}
                    {t.rank}
                  </td>
                  <td>
                    <span>{t.username}</span>
                    {t.verified && (
                      <svg
                        className="verified-badge"
                        aria-label="Verified trader"
                        role="img"
                        viewBox="0 0 24 24"
                        fill="none"
                        stroke="currentColor"
                        strokeWidth="3"
                        strokeLinecap="round"
                        strokeLinejoin="round"
                        width="16"
                        height="16"
                        style={{ verticalAlign: 'middle' }}
                      >
                        <polyline points="20 6 9 17 4 12" />
                      </svg>
                    )}
                  </td>
                  <td
                    style={{ textAlign: 'right' }}
                    className={isPositiveReturn ? 'return-positive' : 'return-negative'}
                  >
                    {(Number(t.return30d) * 100).toFixed(2)}%
                  </td>
                  <td style={{ textAlign: 'right' }}>{(Number(t.winRate) * 100).toFixed(2)}%</td>
                  <td style={{ textAlign: 'right' }}>{t.totalTrades}</td>
                  <td style={{ textAlign: 'right' }}>{t.followers.toLocaleString()}</td>
                  <td>
                    <span className="strategy-tag" aria-label={`Strategy style: ${t.strategy}`}>
                      {t.strategy}
                    </span>
                  </td>
                  <td style={{ textAlign: 'center' }}>
                    <button
                      type="button"
                      className={`follow-button${following[t.username] ? ' following' : ''}`}
                      onClick={() => toggleFollow(t.username)}
                      aria-pressed={following[t.username] ? 'true' : 'false'}
                      aria-label={`${following[t.username] ? 'Unfollow' : 'Follow'} ${t.username}`}
                    >
                      {following[t.username] ? 'Following' : 'Follow'}
                    </button>
                  </td>
                </tr>
              );
            })}
            {sorted.length === 0 && (
              <tr>
                <td colSpan="8" style={{ textAlign: 'center', padding: '24px 0', color: '#90A3AF' }}>
                  No traders found.
                </td>
              </tr>
            )}
          </tbody>
        </table>
      </section>
    </>
  );
};

export default VerifiedLeaderboard;
